import React from 'react'
import GitSaturn from '@/registry/default/git-saturn/components/git-saturn'
import { getGitSaturnDataAction } from '@/registry/default/git-saturn/lib/git-saturn.actions'

async function page() {
  const saturnData = await getGitSaturnDataAction({
    includeCommitCounts: true,
  });

  return (
    <div>
      <GitSaturn
        username={saturnData.username}
        width={720}
        height={420}
        interactive
        repos={saturnData.repos}
      />
    </div>
  )
}

export default page

'use client'

import { cn } from '@/lib/utils'
import { Canvas } from '@react-three/fiber'
import React from 'react'
import { GitSaturnProps, GitSaturnRepo } from '@/registry/default/git-saturn/lib/git-saturn.types'
import { SaturnScene } from '@/registry/default/git-saturn/components/saturn-scene'

export default function GitSaturn({
  repos,
  username = 'developer',
  width = 720,
  height = 420,
  interactive = true,
  className,
  showUsername = true,
  showStats = true,
  showRepoDetails = true,
}: GitSaturnProps) {
  const [focusState, setFocusState] = React.useState<{ repo: GitSaturnRepo | null; locked: boolean }>({
    repo: null,
    locked: false,
  })
  const repoCount = repos.length
  const totalCommits = repos.reduce((sum, repo) => sum + repo.commits, 0)

  const focusedRepo = focusState.repo

  function formatStars(repo: GitSaturnRepo) {
    return repo.stars ?? Math.max(18, Math.round(repo.commits * 1.35 + (repo.name.length % 9) * 11))
  }

  function formatLastActivity(repo: GitSaturnRepo) {
    if (repo.lastActivity) return repo.lastActivity

    const recency = Math.max(1, Math.round(180 / Math.max(18, repo.commits / 2)))
    return `${recency} days ago`
  }

  return (
    <div 
      className={cn('w-(--git-saturn-width) h-(--git-saturn-height)', className)}
      style={{ 
        '--git-saturn-width': `${width}px`, 
        '--git-saturn-height': `${height}px` 
      } as React.CSSProperties}
    >
      <div
        className="relative w-full h-full overflow-hidden rounded-2xl border bg-linear-to-b from-slate-950 to-slate-900"
      >
        <Canvas
          camera={{ position: [0, 0, 6], fov: 48 }}
          onPointerMissed={() => setFocusState({ repo: null, locked: false })}
        >
          <SaturnScene
            repos={repos}
            interactive={interactive}
            focusedRepo={focusedRepo}
            focusLocked={focusState.locked}
            onFocusRepo={(repo, locked = false) => setFocusState({ repo, locked })}
            onClearFocus={(repo) => {
              if (!focusState.locked && focusState.repo?.name === repo.name) {
                setFocusState({ repo: null, locked: false })
              }
            }}
          />
        </Canvas>

        {showUsername && (
          <div className="pointer-events-none absolute left-4 top-4 rounded-full border bg-background/85 px-3 py-1 text-xs font-medium shadow-sm backdrop-blur">
            {username}
          </div>
        )}

        {showStats && (
          <div className="pointer-events-none absolute bottom-4 left-1/2 -translate-x-1/2 rounded-full border bg-background/85 px-3 py-1 text-xs font-medium shadow-sm backdrop-blur">
            {totalCommits.toLocaleString()} commits / {repoCount} repos
          </div>
        )}

        {showRepoDetails && focusedRepo ? (
          <div className="cursor-pointer absolute right-4 top-4 rounded-2xl border bg-background/90 px-3 py-2 text-left shadow-sm backdrop-blur">
            <div className="mt-1 text-sm font-medium">{focusedRepo.name}</div>
            <div className="text-xs text-muted-foreground">{focusedRepo.commits.toLocaleString()} commits</div>
            <div className="mt-2 grid gap-1 text-xs text-muted-foreground">
              <div>{formatStars(focusedRepo).toLocaleString()} stars</div>
              <div>Last activity {formatLastActivity(focusedRepo)}</div>
            </div>
          </div>
        ) : null}
      </div>
    </div>
  )
}

'use client'

import { OrbitControls } from '@react-three/drei'
import { useFrame } from '@react-three/fiber'
import React from 'react'
import * as THREE from 'three'
import { SaturnPlanet } from '@/registry/default/git-saturn/components/git-saturn-planet'
import { RepoRing } from '@/registry/default/git-saturn/components/repo-ring'
import { useThree } from '@react-three/fiber'
import { GitSaturnRepo } from '@/registry/default/git-saturn/lib/git-saturn.types'
import { StarField } from '@/registry/default/git-saturn/components/star-field'

function clamp(value: number, min: number, max: number) {
  return Math.min(max, Math.max(min, value))
}

export function SaturnScene({
  repos,
  interactive,
  focusedRepo,
  focusLocked,
  onFocusRepo,
  onClearFocus,
}: {
  repos: GitSaturnRepo[]
  interactive: boolean
  focusedRepo: GitSaturnRepo | null
  focusLocked: boolean
  onFocusRepo: (repo: GitSaturnRepo | null, locked?: boolean) => void
  onClearFocus: (repo: GitSaturnRepo) => void
}) {
  const systemRef = React.useRef<THREE.Group>(null)
  const controlsRef = React.useRef<any>(null)
  const { camera } = useThree()
  const repoCount = repos.length
  const ringRadius = 1.95 + clamp(repoCount * 0.02, 0, 0.8)
  const spinSpeed = 0.08 + repoCount * 0.003
  const shouldPauseSpin = focusedRepo !== null && !focusLocked

  useFrame(({ clock }, delta) => {
    if (!systemRef.current) return

    const elapsed = clock.getElapsedTime()
    if (interactive && elapsed < 4) {
      const progress = elapsed / 4
      const eased = progress * progress * (3 - 2 * progress)
      const orbitAngle = 0.25 + eased * 1.5
      const orbitRadius = 7.7 - eased * 1.35
      const cameraHeight = 1.65 + Math.sin(eased * Math.PI) * 0.35

      camera.position.set(
        Math.cos(orbitAngle) * orbitRadius,
        cameraHeight,
        Math.sin(orbitAngle) * orbitRadius
      )
      camera.lookAt(0, 0.1, 0)
      if (controlsRef.current) {
        controlsRef.current.target.set(0, 0.1, 0)
        controlsRef.current.update()
        controlsRef.current.enabled = false
      }
    } else if (controlsRef.current) {
      controlsRef.current.target.set(0, 0.1, 0)
      controlsRef.current.enabled = interactive
      controlsRef.current.update()
    }

    if (!shouldPauseSpin) {
      systemRef.current.rotation.y += delta * spinSpeed
    }
  })

  return (
    <>
      <StarField />
      <ambientLight intensity={0.44} />
      <directionalLight position={[3, 2, 4]} intensity={1.15} />
      <pointLight position={[-3, -1.5, -2]} intensity={0.45} color="#93c5fd" />
      <pointLight position={[0, 3, 1]} intensity={0.18} color="#67e8f9" />

      <group ref={systemRef} rotation={[THREE.MathUtils.degToRad(-18), THREE.MathUtils.degToRad(24), 0]}>
        <SaturnPlanet radius={1.22} />
        <RepoRing
          repos={repos}
          ringRadius={ringRadius}
          spinSpeed={spinSpeed}
          focusedRepo={focusedRepo}
          focusLocked={focusLocked}
          onFocusRepo={onFocusRepo}
          onClearFocus={onClearFocus}
        />
      </group>

      {interactive ? (
        <OrbitControls
          ref={controlsRef}
          enablePan={false}
          enableZoom
          enableDamping
          dampingFactor={0.08}
          minDistance={3.1}
          maxDistance={8.5}
        />
      ) : null}
    </>
  )
}

'use client'

import { useFrame } from '@react-three/fiber'
import React from 'react'
import * as THREE from 'three'

type StarData = {
  position: [number, number, number]
  size: number
  twinkleSpeed: number
  twinklePhase: number
  baseOpacity: number
  spikeScale: number
}

function createStarData(count: number): StarData[] {
  return Array.from({ length: count }, () => {
    const radius = 8 + Math.random() * 20
    const theta = Math.acos(1 - 2 * Math.random())
    const phi = Math.random() * Math.PI * 2
    const x = radius * Math.sin(theta) * Math.cos(phi)
    const y = radius * Math.cos(theta)
    const z = radius * Math.sin(theta) * Math.sin(phi)
    const size = 0.004 + Math.random() * 0.02

    return {
      position: [x, y, z],
      size,
      twinkleSpeed: 0.6 + Math.random() * 2.4,
      twinklePhase: Math.random() * Math.PI * 2,
      baseOpacity: 0.26 + Math.random() * 0.62,
      spikeScale: 2 + Math.random() * 3.8,
    }
  })
}

function TwinklingStar({ data }: { data: StarData }) {
  const coreRef = React.useRef<THREE.Mesh>(null)
  const spikeARef = React.useRef<THREE.Mesh>(null)
  const spikeBRef = React.useRef<THREE.Mesh>(null)

  useFrame(({ clock }) => {
    const t = clock.getElapsedTime()
    const pulse = (Math.sin(t * data.twinkleSpeed + data.twinklePhase) + 1) * 0.5
    const shimmer = 0.75 + pulse * 0.45
    const opacity = data.baseOpacity * (0.55 + pulse * 0.65)

    if (coreRef.current) {
      coreRef.current.scale.setScalar(shimmer)
      ;(coreRef.current.material as THREE.MeshBasicMaterial).opacity = opacity
    }

    if (spikeARef.current) {
      spikeARef.current.scale.set(1 + pulse * 0.8, data.spikeScale + pulse * 0.5, 1)
      ;(spikeARef.current.material as THREE.MeshBasicMaterial).opacity = opacity * 0.65
    }

    if (spikeBRef.current) {
      spikeBRef.current.scale.set(1 + pulse * 0.8, data.spikeScale * 0.85 + pulse * 0.45, 1)
      ;(spikeBRef.current.material as THREE.MeshBasicMaterial).opacity = opacity * 0.55
    }
  })

  return (
    <group position={data.position}>
      <mesh ref={spikeARef}>
        <planeGeometry args={[data.size * 0.22, data.size * 2.8]} />
        <meshBasicMaterial color="#f8fafc" transparent opacity={0.25} depthWrite={false} toneMapped={false} />
      </mesh>
      <mesh ref={spikeBRef} rotation={[0, 0, Math.PI / 2]}>
        <planeGeometry args={[data.size * 0.22, data.size * 2.3]} />
        <meshBasicMaterial color="#e2e8f0" transparent opacity={0.2} depthWrite={false} toneMapped={false} />
      </mesh>
      <mesh ref={coreRef}>
        <sphereGeometry args={[data.size, 8, 8]} />
        <meshBasicMaterial color="#ffffff" transparent opacity={0.5} depthWrite={false} toneMapped={false} />
      </mesh>
    </group>
  )
}

function ShootingStars({ count = 4 }: { count?: number }) {
  const refs = React.useRef<(THREE.Mesh | null)[]>([])
  const states = React.useRef(
    Array.from({ length: count }, () => ({
      active: false,
      delay: 0.8 + Math.random() * 5,
      life: 0,
      lifeMax: 0,
      velocity: new THREE.Vector3(),
    }))
  )

  useFrame((_, delta) => {
    for (let i = 0; i < count; i += 1) {
      const mesh = refs.current[i]
      const state = states.current[i]
      if (!mesh) continue

      if (!state.active) {
        state.delay -= delta
        mesh.visible = false

        if (state.delay <= 0) {
          state.active = true
          state.life = 0
          state.lifeMax = 0.6 + Math.random() * 1.2
          state.delay = 2 + Math.random() * 7
          mesh.visible = true

          mesh.position.set((Math.random() - 0.5) * 28, 3 + Math.random() * 8, -6 - Math.random() * 16)

          state.velocity.set(-(3.5 + Math.random() * 3), -(0.6 + Math.random() * 1.8), -0.2 - Math.random() * 0.8)
        }

        continue
      }

      state.life += delta
      if (state.life >= state.lifeMax) {
        state.active = false
        mesh.visible = false
        continue
      }

      mesh.position.addScaledVector(state.velocity, delta)
      const progress = state.life / state.lifeMax
      const opacity = Math.max(0, 1 - progress)
      ;(mesh.material as THREE.MeshBasicMaterial).opacity = opacity * 0.75
      mesh.scale.set(1 + progress * 2.8, 1, 1)
    }
  })

  return (
    <group>
      {Array.from({ length: count }).map((_, index) => (
        <mesh
          key={index}
          ref={(element) => {
            refs.current[index] = element
          }}
          visible={false}
        >
          <planeGeometry args={[0.08, 0.012]} />
          <meshBasicMaterial color="#f8fafc" transparent opacity={0} depthWrite={false} toneMapped={false} />
        </mesh>
      ))}
    </group>
  )
}

export function StarField() {
  const stars = React.useMemo(() => createStarData(320), [])

  return (
    <group>
      {stars.map((star, index) => (
        <TwinklingStar key={index} data={star} />
      ))}
      <ShootingStars count={5} />
    </group>
  )
}

'use client'

import React from 'react'
import * as THREE from 'three'

function seeded(seed: number) {
  const x = Math.sin(seed) * 10000
  return x - Math.floor(x)
}

function buildMeteoroidGeometry(radius: number, seed: number) {
  const geometry = new THREE.IcosahedronGeometry(radius, 5)
  const position = geometry.attributes.position
  const vertex = new THREE.Vector3()

  const craterCenters = Array.from({ length: 7 }, (_, index) => {
    const s = seed + index * 17.13
    const theta = seeded(s) * Math.PI * 2
    const phi = Math.acos(2 * seeded(s + 5.21) - 1)

    return {
      center: new THREE.Vector3(
        Math.sin(phi) * Math.cos(theta),
        Math.cos(phi),
        Math.sin(phi) * Math.sin(theta)
      ),
      size: 0.28 + seeded(s + 9.07) * 0.2,
      depth: 0.06 + seeded(s + 11.9) * 0.08,
    }
  })

  for (let i = 0; i < position.count; i += 1) {
    vertex.fromBufferAttribute(position, i)
    const normal = vertex.clone().normalize()

    const noise = (
      Math.sin((normal.x + seed * 0.37) * 8.1) +
      Math.sin((normal.y - seed * 0.21) * 9.4) +
      Math.sin((normal.z + seed * 0.11) * 7.7)
    ) / 3

    let displacement = 1 + noise * 0.2

    for (const crater of craterCenters) {
      const distance = normal.distanceTo(crater.center)
      if (distance < crater.size) {
        const influence = 1 - distance / crater.size
        displacement -= influence * crater.depth
      }
    }

    vertex.copy(normal.multiplyScalar(radius * displacement))
    position.setXYZ(i, vertex.x, vertex.y, vertex.z)
  }

  geometry.computeVertexNormals()
  return geometry
}

export function Meteoroid({
  radius,
  seed,
}: {
  radius: number
  seed: number
}) {
  const geometry = React.useMemo(() => buildMeteoroidGeometry(radius, seed), [radius, seed])

  React.useEffect(() => {
    return () => {
      geometry.dispose()
    }
  }, [geometry])

  return (
    <mesh geometry={geometry}>
      <meshStandardMaterial
        color="#9ca3af"
        roughness={0.92}
        metalness={0.04}
        emissive="#1e293b"
        emissiveIntensity={0.08}
      />
    </mesh>
  )
}

'use client'

import React from 'react'
import * as THREE from 'three'

function makeSaturnTextures() {
  const width = 1024
  const height = 512

  const colorCanvas = document.createElement('canvas')
  colorCanvas.width = width
  colorCanvas.height = height
  const colorCtx = colorCanvas.getContext('2d')

  const bumpCanvas = document.createElement('canvas')
  bumpCanvas.width = width
  bumpCanvas.height = height
  const bumpCtx = bumpCanvas.getContext('2d')

  if (!colorCtx || !bumpCtx) {
    return null
  }

  const colorGradient = colorCtx.createLinearGradient(0, 0, 0, height)
  colorGradient.addColorStop(0, '#d5cfb4')
  colorGradient.addColorStop(0.18, '#c9c29f')
  colorGradient.addColorStop(0.35, '#bcae85')
  colorGradient.addColorStop(0.52, '#d2c59f')
  colorGradient.addColorStop(0.68, '#b59f79')
  colorGradient.addColorStop(0.84, '#c8b690')
  colorGradient.addColorStop(1, '#a8926f')
  colorCtx.fillStyle = colorGradient
  colorCtx.fillRect(0, 0, width, height)

  bumpCtx.fillStyle = '#7f7f7f'
  bumpCtx.fillRect(0, 0, width, height)

  for (let i = 0; i < 120; i += 1) {
    const y = (i / 120) * height
    const stripeHeight = 2 + Math.random() * 8
    const alpha = 0.04 + Math.random() * 0.1
    const lightBand = Math.random() > 0.45

    colorCtx.fillStyle = lightBand
      ? `rgba(244, 228, 179, ${alpha})`
      : `rgba(162, 142, 108, ${alpha})`
    colorCtx.fillRect(0, y, width, stripeHeight)

    bumpCtx.fillStyle = lightBand
      ? `rgba(172, 172, 172, ${alpha})`
      : `rgba(118, 118, 118, ${alpha})`
    bumpCtx.fillRect(0, y, width, stripeHeight)
  }

  for (let i = 0; i < 18; i += 1) {
    const cx = Math.random() * width
    const cy = Math.random() * height
    const radius = 18 + Math.random() * 56

    colorCtx.fillStyle = `rgba(168, 146, 110, ${0.04 + Math.random() * 0.05})`
    colorCtx.beginPath()
    colorCtx.ellipse(cx, cy, radius, radius * 0.42, Math.random() * Math.PI, 0, Math.PI * 2)
    colorCtx.fill()

    bumpCtx.fillStyle = `rgba(122, 122, 122, ${0.05 + Math.random() * 0.06})`
    bumpCtx.beginPath()
    bumpCtx.ellipse(cx, cy, radius * 0.9, radius * 0.4, Math.random() * Math.PI, 0, Math.PI * 2)
    bumpCtx.fill()
  }

  const colorMap = new THREE.CanvasTexture(colorCanvas)
  colorMap.wrapS = THREE.RepeatWrapping
  colorMap.wrapT = THREE.ClampToEdgeWrapping
  colorMap.anisotropy = 8

  const bumpMap = new THREE.CanvasTexture(bumpCanvas)
  bumpMap.wrapS = THREE.RepeatWrapping
  bumpMap.wrapT = THREE.ClampToEdgeWrapping
  bumpMap.anisotropy = 8

  return { colorMap, bumpMap }
}

export function SaturnPlanet({ radius }: { radius: number }) {
  const textures = React.useMemo(() => makeSaturnTextures(), [])

  React.useEffect(() => {
    return () => {
      textures?.colorMap.dispose()
      textures?.bumpMap.dispose()
    }
  }, [textures])

  return (
    <mesh>
      <sphereGeometry args={[radius, 128, 128]} />
      <meshStandardMaterial
        map={textures?.colorMap}
        bumpMap={textures?.bumpMap}
        bumpScale={radius * 0.04}
        roughness={0.82}
        metalness={0.03}
      />
    </mesh>
  )
}

'use client'

import { Meteoroid } from '@/registry/default/git-saturn/components/git-meteoroid'
import { useFrame } from '@react-three/fiber'
import React from 'react'
import * as THREE from 'three'
import type { GitSaturnRepo } from '@/registry/default/git-saturn/lib/git-saturn.types'

function seeded(seed: number) {
  const x = Math.sin(seed * 12.9898 + 78.233) * 43758.5453123
  return x - Math.floor(x)
}

function sizeFromCommits(commits: number, minCommits: number, maxCommits: number) {
  if (maxCommits <= minCommits) return 0.04
  const normalized = (commits - minCommits) / (maxCommits - minCommits)
  const curved = Math.pow(normalized, 0.72)
  return 0.02 + curved * 0.062
}

function getRepoPose(index: number, total: number, ringRadius: number, repoCommits: number) {
  const baseAngle = (index / Math.max(1, total)) * Math.PI * 2
  const radialOffset = (seeded(index * 1.71 + repoCommits * 0.19) - 0.5) * 0.06
  const verticalOffset = (seeded(index * 2.33 + repoCommits * 0.13) - 0.5) * 0.04

  return {
    baseAngle,
    radialOffset,
    verticalOffset,
    radius: ringRadius + radialOffset,
  }
}

function RingDust({ count, radius, spread }: { count: number; radius: number; spread: number }) {
  const pointsRef = React.useRef<THREE.Points>(null)
  const positions = React.useMemo(() => {
    const arr = new Float32Array(count * 3)
    for (let i = 0; i < count; i += 1) {
      const angle = Math.random() * Math.PI * 2
      const localRadius = radius + (Math.random() - 0.5) * spread
      const x = Math.cos(angle) * localRadius
      const y = (Math.random() - 0.5) * 0.035
      const z = Math.sin(angle) * localRadius
      arr[i * 3] = x
      arr[i * 3 + 1] = y
      arr[i * 3 + 2] = z
    }
    return arr
  }, [count, radius, spread])

  useFrame((_, delta) => {
    if (!pointsRef.current) return
    pointsRef.current.rotation.y += delta * 0.008
  })

  return (
    <points ref={pointsRef}>
      <bufferGeometry>
        <bufferAttribute attach="attributes-position" args={[positions, 3]} />
      </bufferGeometry>
      <pointsMaterial
        color="#cbd5e1"
        size={0.012}
        sizeAttenuation
        transparent
        opacity={0.5}
        depthWrite={false}
      />
    </points>
  )
}

function RepoRock({
  repo,
  index,
  total,
  ringRadius,
  minCommits,
  maxCommits,
  isFocused,
  focusLocked,
  onFocusRepo,
  onClearFocus,
}: {
  repo: GitSaturnRepo
  index: number
  total: number
  ringRadius: number
  minCommits: number
  maxCommits: number
  isFocused: boolean
  focusLocked: boolean
  onFocusRepo: (repo: GitSaturnRepo | null, locked?: boolean) => void
  onClearFocus: (repo: GitSaturnRepo) => void
}) {
  const meshRef = React.useRef<THREE.Mesh>(null)

  const cfg = React.useMemo(() => {
    const pose = getRepoPose(index, total, ringRadius, repo.commits)
    const spinX = 0.2 + seeded(index * 3.1) * 0.6
    const spinY = 0.25 + seeded(index * 4.3) * 0.7
    const jitterPhase = seeded(index * 5.7) * Math.PI * 2
    const jitterSpeed = 0.4 + seeded(index * 6.9) * 0.8
    return {
      ...pose,
      spinX,
      spinY,
      jitterPhase,
      jitterSpeed,
    }
  }, [index, repo.commits, ringRadius, total])

  const radius = React.useMemo(
    () => sizeFromCommits(repo.commits, minCommits, maxCommits),
    [repo.commits, minCommits, maxCommits]
  )

  useFrame(({ clock }, delta) => {
    if (!meshRef.current) return
    const t = clock.getElapsedTime()
    const tinyJitter = Math.sin(t * cfg.jitterSpeed + cfg.jitterPhase) * 0.008

    const r = cfg.radius + tinyJitter
    const x = Math.cos(cfg.baseAngle) * r
    const y = cfg.verticalOffset + tinyJitter * 0.5
    const z = Math.sin(cfg.baseAngle) * r

    meshRef.current.position.set(x, y, z)
    meshRef.current.rotation.x += delta * cfg.spinX
    meshRef.current.rotation.y += delta * cfg.spinY

    const targetScale = isFocused ? 1.22 : 1
    meshRef.current.scale.lerp(new THREE.Vector3(targetScale, targetScale, targetScale), 0.12)
  })

  return (
    <mesh
      ref={meshRef}
      onPointerOver={(event) => {
        event.stopPropagation()
        onFocusRepo(repo, false)
      }}
      onPointerOut={(event) => {
        event.stopPropagation()
        if (!focusLocked) {
          onClearFocus(repo)
        }
      }}
      onClick={(event) => {
        event.stopPropagation()
        onFocusRepo(repo, true)
      }}
    >
      <Meteoroid radius={radius} seed={index * 13.31 + repo.commits * 0.17} />
    </mesh>
  )
}

function CommitBurst({
  repo,
  index,
  total,
  ringRadius,
  spinSpeed,
  minCommits,
  maxCommits,
}: {
  repo: GitSaturnRepo
  index: number
  total: number
  ringRadius: number
  spinSpeed: number
  minCommits: number
  maxCommits: number
}) {
  const burstRef = React.useRef<THREE.Mesh>(null)
  const stateRef = React.useRef({
    delay: 0.5 + seeded(index * 4.4) * 1.8,
    life: 0,
    lifeMax: 0.45,
    active: false,
    velocity: new THREE.Vector3(),
  })

  const normalized = maxCommits > minCommits ? (repo.commits - minCommits) / (maxCommits - minCommits) : 0
  const burstStrength = Math.max(0, normalized - 0.35)
  const burstEnabled = burstStrength > 0

  const pose = React.useMemo(() => getRepoPose(index, total, ringRadius, repo.commits), [index, repo.commits, ringRadius, total])

  useFrame((_, delta) => {
    const mesh = burstRef.current
    if (!mesh || !burstEnabled) return

    const state = stateRef.current
    const t = performance.now() * 0.001
    const angle = pose.baseAngle + t * spinSpeed
    const frontArc = Math.max(0, Math.sin(angle))

    if (!state.active) {
      state.delay -= delta
      mesh.visible = false

      if (state.delay <= 0 && frontArc > 0.35) {
        state.active = true
        state.life = 0
        state.lifeMax = 0.22 + burstStrength * 0.36
        state.delay = 0.9 + (1 - burstStrength) * 1.8 + seeded(index * 8.1) * 0.8
        mesh.visible = true

        const tangentX = -Math.sin(angle)
        const tangentZ = Math.cos(angle)
        const baseRadius = pose.radius + 0.04
        mesh.position.set(
          Math.cos(angle) * baseRadius + tangentX * 0.045,
          pose.verticalOffset + Math.sin(t * 2.1 + index) * 0.01,
          Math.sin(angle) * baseRadius + tangentZ * 0.045
        )

        state.velocity.set(tangentX * (0.12 + burstStrength * 0.16), 0.01 + burstStrength * 0.015, tangentZ * (0.12 + burstStrength * 0.16))
      }

      return
    }

    state.life += delta
    if (state.life >= state.lifeMax) {
      state.active = false
      mesh.visible = false
      return
    }

    mesh.position.addScaledVector(state.velocity, delta)
    const progress = state.life / state.lifeMax
    const opacity = Math.max(0, (1 - progress) * burstStrength * 0.85)
    mesh.scale.setScalar(0.7 + progress * 1.5)
    ;(mesh.material as THREE.MeshBasicMaterial).opacity = opacity
  })

  if (!burstEnabled) return null

  return (
    <mesh ref={burstRef} visible={false}>
      <sphereGeometry args={[0.012 + burstStrength * 0.01, 8, 8]} />
      <meshBasicMaterial color="#f8fafc" transparent opacity={0} depthWrite={false} toneMapped={false} />
    </mesh>
  )
}

export function RepoRing({
  repos,
  ringRadius,
  spinSpeed,
  focusedRepo,
  focusLocked,
  onFocusRepo,
  onClearFocus,
}: {
  repos: GitSaturnRepo[]
  ringRadius: number
  spinSpeed: number
  focusedRepo: GitSaturnRepo | null
  focusLocked: boolean
  onFocusRepo: (repo: GitSaturnRepo | null, locked?: boolean) => void
  onClearFocus: (repo: GitSaturnRepo) => void
}) {
  const minCommits = repos.reduce((min, repo) => Math.min(min, repo.commits), Number.POSITIVE_INFINITY)
  const maxCommits = repos.reduce((max, repo) => Math.max(max, repo.commits), 0)

  return (
    <group>
      <RingDust count={100} radius={ringRadius} spread={0.14} />
      {repos.map((repo, index) => (
        <RepoRock
          key={repo.name}
          repo={repo}
          index={index}
          total={repos.length}
          ringRadius={ringRadius}
          minCommits={minCommits}
          maxCommits={maxCommits}
          isFocused={focusedRepo?.name === repo.name}
          focusLocked={focusLocked}
          onFocusRepo={onFocusRepo}
          onClearFocus={onClearFocus}
        />
      ))}
      {repos.map((repo, index) => (
        <CommitBurst
          key={`${repo.name}-burst`}
          repo={repo}
          index={index}
          total={repos.length}
          ringRadius={ringRadius}
          spinSpeed={spinSpeed}
          minCommits={minCommits}
          maxCommits={maxCommits}
        />
      ))}
    </group>
  )
}

